import React from 'react';
import { Carousel, CarouselItem } from '@salutejs/plasma-web';
import styled from 'styled-components';
export function App() {
    const StyledCard = styled.div`
        display: flex;
        align-items: center;
        justify-content: center;
        border-radius: 8px;
        width: 400px;
        height: 370px;
        background-color: #add8e6;
        font-size: 30px;
    `;
    const items = Array(10)
        .fill(1)
        .map((_, i) => ({
            id: i,
            title: i,
        }));
    return (
        <div style={{ display: 'block', width: '600px' }}>
            <Carousel>
                {items.map((item, i) => (
                    <CarouselItem key={i}>
                        <StyledCard>{item.title}</StyledCard>
                    </CarouselItem>
                ))}
            </Carousel>
        </div>
    );
}
